	reportBut.grid(row=0,column=2)

	#process of image feedback
	global image_feedback
	image_feedback = imageprocess(images_icon["feedback"],size=20)
	feedbackBut = tk.Label(status,image=image_feedback,bg="white")
	feedbackBut.grid(row=0,column=3)

	#process of image calculate
	global image_calculate
	image_calculate = imageprocess(images_icon["calculator"],size=20)
	calcBut = tk.Label(status,image=image_calculate,font=(font,16),bg="white")
	calcBut.grid(row=0,column=0)

	#process of image info
	global imginfo
	imginfo = imageprocess(images_icon["info"],size=20)
	infoBut = tk.Label(status,image=imginfo,font=("avenir",16),bg="white")
	infoBut.grid(row=0,column=77)

	#process of image advanced
	global image_adv
	image_adv = imageprocess(images_icon["advanced"],size=20)
	advBut = tk.Label(status,image=image_adv,font=(font,16),bg="white")
	advBut.grid(row=0,column=1)
	
	#declaring weights for status bar 
	for i in range(0,80):
		status.grid_columnconfigure(i,weight=1)	


	#tooltip for all the status bar menu items
	#help
	ttx.Tooltip(bg="white",widget=helpBut,text="Help Center",font=(font,10))
	#calculate
	ttx.Tooltip(bg="white",widget=calcBut,text="Calculate",function=lambda: startcalculate(master=window_base,current=window,reinsert=putback,icon=imgbackb,data=data,data2=data2),font=(font,10))
	#feedback ttx.Tooltip(bg="white",widget=feedbackBut,text="Feedback",function=lambda: startfeedback(master=window_base,current=window,reinsert=putback,icon=imgbackb),font=(font,10))
	#report ttx.Tooltip(bg="white",widget=reportBut,text="Report Error",function=lambda: startreport(master=window_base,current=window,reinsert=putback,icon=imgbackb),font=(font,10))
	ttx.Tooltip(bg="white",widget=feedbackBut,text="Feedback",function=lambda: webbrowser.open("https://github.com/wiredfuturelabs/Henry-Molar/issues"))	
	ttx.Tooltip(bg="white",widget=reportBut,text="Report Issue",function=lambda: webbrowser.open("https://github.com/wiredfuturelabs/Henry-Molar/issues"))
	#builder panel
	ttx.Tooltip(bg="white",widget=advBut,text="Builder Panel",function=lambda: advancedpanel(base=window_base,current=window,reinsert=putback,data=data,data2=data2,icon=imgsearch),font=(font,10))
	#about
	ttx.Tooltip(bg="white",widget=infoBut,text="About",function=info,font=(font,10))

	#configuring the color of all the borders and lanthanide actinide
	for widgets in [window,lanth,act,borderleft,borderright]:
		widgets.config(bg=ttx.rgb(23,27,33))
		try: widgets.config(fg="white")
		except: pass

